class Solution {
    private static final int MOD = 1000000007;

    private int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    public int distinctSequences(int n) {
        if (n == 1) return 6;
        int[][] prevDp = new int[7][7];
        for (int i = 1; i <= 6; i++) {
            for (int j = 1; j <= 6; j++) {
                if (i != j && gcd(i, j) == 1) {
                    prevDp[i][j] = 1;
                }
            }
        }

        for (int step = 3; step <= n; step++) {
            int[][] nextDp = new int[7][7];
            for (int a = 1; a <= 6; a++) {
                for (int b = 1; b <= 6; b++) {
                    if (prevDp[a][b] == 0) continue;
                    for (int c = 1; c <= 6; c++) {
                        if (gcd(b, c) == 1 && c != a) {
                            nextDp[b][c] = (nextDp[b][c] + prevDp[a][b]) % MOD;
                        }
                    }
                }
            }
            prevDp = nextDp;
        }

        long total = 0;
        for (int i = 1; i <= 6; i++) {
            for (int j = 1; j <= 6; j++) {
                total = (total + prevDp[i][j]) % MOD;
            }
        }
        return (int) total;
    }
}

